// Donate.js
import React from "react";

function Donate() {
  const handleDonateClick = () => {
    // Replace with your donation link
    window.location.href = "https://www.yourdonatelink.com";
  };

  return (
    <button
      onClick={handleDonateClick}
      className="py-2 px-6 bg-green-500 hover:bg-green-500 text-white font-bold rounded-lg shadow-lg transition-colors duration-300"
    >
      Donate
    </button>
  );
}

export default Donate;
